 2→//  TrainerChatView.swift
 3→//  FitToday
 4→//
 5→//  Chat interface for communicating with a personal trainer.
 6→//
 7→
 8→import SwiftUI
 9→
10→struct TrainerChatView: View {
11→    @State private var viewModel: TrainerChatViewModel
12→
13→    init(trainerId: String, trainerName: String) {
14→        _viewModel = State(wrappedValue: TrainerChatViewModel(trainerId: trainerId, trainerName: trainerName))
15→    }
16→
17→    var body: some View {
18→        VStack(spacing: 0) {
19→            // Messages
20→            ScrollViewReader { proxy in
21→                ScrollView {
22→                    LazyVStack(spacing: FitTodaySpacing.sm) {
23→                        ForEach(viewModel.messages) { message in
24→                            ChatBubble(
25→                                message: message,
26→                                isFromCurrentUser: !message.isFromTrainer
27→                            )
28→                            .id(message.id)
29→                        }
30→                    }
31→                    .padding(.horizontal, FitTodaySpacing.md)
32→                    .padding(.vertical, FitTodaySpacing.sm)
33→                }
34→                .scrollIndicators(.hidden)
35→                .onChange(of: viewModel.messages.count) {
36→                    if let lastId = viewModel.messages.last?.id {
37→                        withAnimation {
38→                            proxy.scrollTo(lastId, anchor: .bottom)
39→                        }
40→                    }
41→                }
42→            }
43→
44→            Divider()
45→                .overlay(FitTodayColor.outline)
46→
47→            // Input Bar
48→            inputBar
49→        }
50→        .background(FitTodayColor.background)
51→    }
52→
53→    // MARK: - Input Bar
54→
55→    private var inputBar: some View {
56→        HStack(spacing: FitTodaySpacing.sm) {
57→            TextField("trainer.chat.placeholder".localized, text: $viewModel.newMessageText, axis: .vertical)
58→                .font(FitTodayFont.ui(size: 14, weight: .medium))
59→                .foregroundStyle(FitTodayColor.textPrimary)
60→                .lineLimit(1...4)
61→                .padding(.horizontal, FitTodaySpacing.md)
62→                .padding(.vertical, 10)
63→                .background(FitTodayColor.surface)
64→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
65→
66→            Button {
67→                viewModel.sendMessage()
68→            } label: {
69→                Image(systemName: "arrow.up.circle.fill")
70→                    .font(.system(size: 32))
71→                    .foregroundStyle(viewModel.canSend ? FitTodayColor.brandPrimary : FitTodayColor.textTertiary)
72→            }
73→            .buttonStyle(.plain)
74→            .disabled(!viewModel.canSend)
75→        }
76→        .padding(.horizontal, FitTodaySpacing.md)
77→        .padding(.vertical, FitTodaySpacing.sm)
78→        .background(FitTodayColor.backgroundElevated)
79→    }
80→}
