  1→//
  2→//  TrainerDashboardView.swift
  3→//  FitToday
  4→//
  5→//  Dashboard view with trainer header and segmented tabs.
  6→//
  7→
  8→import SwiftUI
  9→
 10→struct TrainerDashboardView: View {
 11→    let trainer: PersonalTrainer
 12→    let workouts: [TrainerWorkout]
 13→    let isChatEnabled: Bool
 14→    let onDisconnect: () -> Void
 15→    let initialTab: TrainerDashboardTab
 16→
 17→    @State private var selectedTab: TrainerDashboardTab
 18→
 19→    init(
 20→        trainer: PersonalTrainer,
 21→        workouts: [TrainerWorkout],
 22→        isChatEnabled: Bool,
 23→        onDisconnect: @escaping () -> Void,
 24→        initialTab: TrainerDashboardTab = .today
 25→    ) {
 26→        self.trainer = trainer
 27→        self.workouts = workouts
 28→        self.isChatEnabled = isChatEnabled
 29→        self.onDisconnect = onDisconnect
 30→        self.initialTab = initialTab
 31→        self._selectedTab = State(wrappedValue: initialTab)
 32→    }
 33→
 34→    var body: some View {
 35→        VStack(spacing: 0) {
 36→            trainerHeader
 37→            tabPicker
 38→            tabContent
 39→        }
 40→        .background(FitTodayColor.background)
 41→    }
 42→
 43→    // MARK: - Trainer Header
 44→
 45→    private var trainerHeader: some View {
 46→        HStack(spacing: FitTodaySpacing.md) {
 47→            trainerAvatar
 48→
 49→            VStack(alignment: .leading, spacing: FitTodaySpacing.xs) {
 50→                Text(trainer.displayName)
 51→                    .font(FitTodayFont.ui(size: 18, weight: .bold))
 52→                    .foregroundStyle(FitTodayColor.textPrimary)
 53→                    .lineLimit(1)
 54→
 55→                HStack(spacing: FitTodaySpacing.xs) {
 56→                    Circle()
 57→                        .fill(FitTodayColor.success)
 58→                        .frame(width: 8, height: 8)
 59→
 60→                    Text("trainer.dashboard.online".localized)
 61→                        .font(FitTodayFont.ui(size: 13, weight: .medium))
 62→                        .foregroundStyle(FitTodayColor.textSecondary)
 63→                }
 64→            }
 65→
 66→            Spacer()
 67→
 68→            Menu {
 69→                Button(role: .destructive) {
 70→                    onDisconnect()
 71→                } label: {
 72→                    Label("trainer.dashboard.disconnect".localized, systemImage: "person.badge.minus")
 73→                }
 74→            } label: {
 75→                Image(systemName: "ellipsis")
 76→                    .font(.system(size: 16, weight: .medium))
 77→                    .foregroundStyle(FitTodayColor.textSecondary)
 78→                    .frame(width: 32, height: 32)
 79→            }
 80→        }
 81→        .padding(.horizontal, FitTodaySpacing.md)
 82→        .padding(.vertical, FitTodaySpacing.sm)
 83→        .background(FitTodayColor.backgroundElevated)
 84→    }
 85→
 86→    private var trainerAvatar: some View {
 87→        Group {
 88→            if let photoURL = trainer.photoURL {
 89→                AsyncImage(url: photoURL) { image in
 90→                    image.resizable().scaledToFill()
 91→                } placeholder: {
 92→                    avatarPlaceholder
 93→                }
 94→            } else {
 95→                avatarPlaceholder
 96→            }
 97→        }
 98→        .frame(width: 48, height: 48)
 99→        .clipShape(Circle())
100→    }
101→
102→    private var avatarPlaceholder: some View {
103→        Circle()
104→            .fill(FitTodayColor.brandPrimary.opacity(0.2))
105→            .overlay(
106→                Text(String(trainer.displayName.prefix(1)).uppercased())
107→                    .font(FitTodayFont.ui(size: 18, weight: .bold))
108→                    .foregroundStyle(FitTodayColor.brandPrimary)
109→            )
110→    }
111→
112→    // MARK: - Tab Picker
113→
114→    private var tabPicker: some View {
115→        HStack(spacing: 0) {
116→            ForEach(availableTabs, id: \.self) { tab in
117→                Button {
118→                    withAnimation(.easeInOut(duration: 0.2)) {
119→                        selectedTab = tab
120→                    }
121→                } label: {
122→                    VStack(spacing: FitTodaySpacing.sm) {
123→                        Text(tab.title)
124→                            .font(FitTodayFont.ui(size: 14, weight: selectedTab == tab ? .bold : .medium))
125→                            .foregroundStyle(selectedTab == tab ? FitTodayColor.brandPrimary : FitTodayColor.textSecondary)
126→
127→                        Rectangle()
128→                            .fill(selectedTab == tab ? FitTodayColor.brandPrimary : Color.clear)
129→                            .frame(height: 2)
130→                    }
131→                }
132→                .buttonStyle(.plain)
133→                .frame(maxWidth: .infinity)
134→            }
135→        }
136→        .padding(.horizontal, FitTodaySpacing.md)
137→        .padding(.top, FitTodaySpacing.sm)
138→        .background(FitTodayColor.backgroundElevated)
139→    }
140→
141→    // MARK: - Tab Content
142→
143→    @ViewBuilder
144→    private var tabContent: some View {
145→        switch selectedTab {
146→        case .today:
147→            TodayWorkoutTabView(
148→                workouts: workouts,
149→                onViewHistory: { selectedTab = .history }
150→            )
151→        case .chat:
152→            TrainerChatView(trainerId: trainer.id, trainerName: trainer.displayName)
153→        case .history:
154→            TrainerHistoryView(workouts: workouts)
155→        case .evolution:
156→            TrainerEvolutionView(workouts: workouts)
157→        }
158→    }
159→
160→    // MARK: - Helpers
161→
162→    private var availableTabs: [TrainerDashboardTab] {
163→        var tabs: [TrainerDashboardTab] = [.today]
164→        if isChatEnabled {
165→            tabs.append(.chat)
166→        }
167→        tabs.append(contentsOf: [.history, .evolution])
168→        return tabs
169→    }
170→}
171→
172→// MARK: - Dashboard Tab
173→
174→enum TrainerDashboardTab: CaseIterable, Hashable {
175→    case today
176→    case chat
177→    case history
178→    case evolution
179→
180→    var title: String {
181→        switch self {
182→        case .today: return "Hoje"
183→        case .chat: return "trainer.dashboard.tab.chat".localized
184→        case .history: return "trainer.dashboard.tab.history".localized
185→        case .evolution: return "trainer.dashboard.tab.evolution".localized
186→        }
187→    }
188→
189→    var icon: String {
190→        switch self {
191→        case .today: return "doc.fill"
192→        case .chat: return "message.fill"
193→        case .history: return "clock.fill"
194→        case .evolution: return "chart.line.uptrend.xyaxis"
195→        }
196→    }
197→}
