  8→import SwiftUI
  9→import Swinject
 10→
 11→struct PersonalTrainerView: View {
 12→    @Environment(AppRouter.self) private var router
 13→    @Environment(\.dependencyResolver) private var resolver
 14→
 15→    @State private var viewModel: PersonalTrainerViewModel
 16→    @State private var showSearchSheet = false
 17→    private let initialTab: TrainerDashboardTab
 18→
 19→    init(resolver: Resolver, initialTab: TrainerDashboardTab = .today) {
 20→        _viewModel = State(wrappedValue: PersonalTrainerViewModel(resolver: resolver))
 21→        self.initialTab = initialTab
 22→    }
 23→
 24→    var body: some View {
 25→        Group {
 26→            if viewModel.isLoading && viewModel.currentTrainer == nil {
 27→                ScrollView {
 28→                    loadingView.padding()
 29→                }
 30→            } else if !viewModel.isFeatureEnabled {
 31→                ScrollView {
 32→                    featureDisabledView.padding()
 33→                }
 34→            } else if viewModel.hasTrainer, let trainer = viewModel.currentTrainer, viewModel.isConnected {
 35→                TrainerDashboardView(
 36→                    trainer: trainer,
 37→                    workouts: viewModel.assignedWorkouts,
 38→                    isChatEnabled: viewModel.isChatEnabled,
 39→                    onDisconnect: {
 40→                        Task { await viewModel.cancelConnection() }
 41→                    },
 42→                    initialTab: initialTab
 43→                )
 44→            } else if !viewModel.hasTrainer {
 45→                TrainerListView(viewModel: viewModel) { trainer in
 46→                    viewModel.selectedTrainer = trainer
 47→                    viewModel.showConnectionSheet = true
 48→                }
 49→            } else {
 50→                ScrollView {
 51→                    VStack(spacing: FitTodaySpacing.lg) {
 52→                        connectedTrainerSection
 53→                    }
 54→                    .padding()
 55→                }
 56→            }
 57→        }
 58→        .background(FitTodayColor.background.ignoresSafeArea())
 59→        .navigationTitle("personal_trainer.title".localized)
 60→        .onAppear {
 61→            viewModel.onAppear()
 62→        }
 63→        .onDisappear {
 64→            viewModel.onDisappear()
 65→        }
 66→        .sheet(isPresented: $showSearchSheet) {
 67→            TrainerSearchView(viewModel: viewModel)
 68→        }
 69→        .sheet(isPresented: $viewModel.showConnectionSheet) {
 70→            if let trainer = viewModel.selectedTrainer {
 71→                ConnectionRequestSheet(
 72→                    trainer: trainer,
 73→                    isRequesting: viewModel.isRequestingConnection,
 74→                    onConfirm: {
 75→                        Task {
 76→                            let success = await viewModel.requestConnection(to: trainer)
 77→                            if success {
 78→                                showSearchSheet = false
 79→                            }
 80→                        }
 81→                    },
 82→                    onCancel: {
 83→                        viewModel.dismissConnectionSheet()
 84→                    }
 85→                )
 86→                .presentationDetents([.medium, .large])
 87→            }
 88→        }
 89→        .alert(
 90→            "personal_trainer.error.title".localized,
 91→            isPresented: Binding(
 92→                get: { viewModel.error != nil },
 93→                set: { if !$0 { viewModel.clearError() } }
 94→            )
 95→        ) {
 96→            Button("Ok", role: .cancel) {
 97→                viewModel.clearError()
 98→            }
 99→        } message: {
100→            Text(viewModel.error?.localizedDescription ?? "personal_trainer.error.default".localized)
101→        }
102→    }
103→
104→    // MARK: - Loading View
105→
106→    private var loadingView: some View {
107→        VStack(spacing: FitTodaySpacing.md) {
108→            ProgressView()
109→                .tint(FitTodayColor.brandPrimary)
110→            Text("personal_trainer.loading".localized)
111→                .font(FitTodayFont.ui(size: 14, weight: .medium))
112→                .foregroundStyle(FitTodayColor.textSecondary)
113→        }
114→        .frame(maxWidth: .infinity)
115→        .frame(height: 200)
116→    }
117→
118→    // MARK: - Feature Disabled View
119→
120→    private var featureDisabledView: some View {
121→        VStack(spacing: FitTodaySpacing.lg) {
122→            Image(systemName: "person.badge.clock")
123→                .font(.system(size: 64))
124→                .foregroundStyle(FitTodayColor.textSecondary)
125→
126→            Text("personal_trainer.disabled.title".localized)
127→                .font(FitTodayFont.ui(size: 24, weight: .bold))
128→                .foregroundStyle(FitTodayColor.textPrimary)
129→
130→            Text("personal_trainer.disabled.message".localized)
131→                .font(FitTodayFont.ui(size: 16, weight: .medium))
132→                .foregroundStyle(FitTodayColor.textSecondary)
133→                .multilineTextAlignment(.center)
134→        }
135→        .padding()
136→    }
137→
138→    // MARK: - Find Trainer Section
139→
140→    private var findTrainerSection: some View {
141→        VStack(spacing: FitTodaySpacing.xl) {
142→            // Header
143→            VStack(spacing: FitTodaySpacing.sm) {
144→                Image(systemName: "figure.strengthtraining.traditional")
145→                    .font(.system(size: 64))
146→                    .foregroundStyle(FitTodayColor.brandPrimary)
147→
148→                Text("personal_trainer.find.title".localized)
149→                    .font(FitTodayFont.ui(size: 24, weight: .bold))
150→                    .foregroundStyle(FitTodayColor.textPrimary)
151→                    .multilineTextAlignment(.center)
152→
153→                Text("personal_trainer.find.subtitle".localized)
154→                    .font(FitTodayFont.ui(size: 16, weight: .medium))
155→                    .foregroundStyle(FitTodayColor.textSecondary)
156→                    .multilineTextAlignment(.center)
157→            }
158→
159→            // Actions
160→            VStack(spacing: FitTodaySpacing.md) {
161→                Button {
162→                    showSearchSheet = true
163→                } label: {
164→                    HStack {
165→                        Image(systemName: "magnifyingglass")
166→                        Text("personal_trainer.search.button".localized)
167→                    }
168→                }
169→                .fitPrimaryStyle()
170→
171→                // Invite Code Section
172→                VStack(spacing: FitTodaySpacing.sm) {
173→                    Text("personal_trainer.invite.header".localized)
174→                        .font(FitTodayFont.ui(size: 14, weight: .medium))
175→                        .foregroundStyle(FitTodayColor.textSecondary)
176→
177→                    HStack(spacing: FitTodaySpacing.sm) {
178→                        TextField("personal_trainer.invite.placeholder".localized, text: $viewModel.inviteCode)
179→                            .textFieldStyle(.roundedBorder)
180→                            .textCase(.uppercase)
181→                            .autocorrectionDisabled()
182→                            .frame(maxWidth: 200)
183→
184→                        Button {
185→                            Task {
186→                                await viewModel.findByInviteCode()
187→                            }
188→                        } label: {
189→                            if viewModel.isSearching {
190→                                ProgressView()
191→                                    .tint(.white)
192→                            } else {
193→                                Text("personal_trainer.invite.use_button".localized)
194→                            }
195→                        }
196→                        .fitPrimaryStyle()
197→                        .disabled(!viewModel.canUseInviteCode || viewModel.isSearching)
198→                    }
199→                }
200→            }
201→
202→            // Benefits
203→            benefitsSection
204→        }
205→    }
206→
207→    // MARK: - Benefits Section
208→
209→    private var benefitsSection: some View {
210→        VStack(alignment: .leading, spacing: FitTodaySpacing.md) {
211→            Text("personal_trainer.benefits.title".localized)
212→                .font(FitTodayFont.ui(size: 18, weight: .bold))
213→                .foregroundStyle(FitTodayColor.textPrimary)
214→
215→            benefitRow(icon: "dumbbell.fill", title: "personal_trainer.benefits.workouts.title".localized, description: "personal_trainer.benefits.workouts.description".localized)
216→
217→            benefitRow(icon: "chart.line.uptrend.xyaxis", title: "personal_trainer.benefits.tracking.title".localized, description: "personal_trainer.benefits.tracking.description".localized)
218→
219→            benefitRow(icon: "message.fill", title: "personal_trainer.benefits.communication.title".localized, description: "personal_trainer.benefits.communication.description".localized)
220→
221→            benefitRow(icon: "calendar", title: "personal_trainer.benefits.schedule.title".localized, description: "personal_trainer.benefits.schedule.description".localized)
222→        }
223→        .padding()
224→        .background(FitTodayColor.surface)
225→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.lg))
226→    }
227→
228→    private func benefitRow(icon: String, title: String, description: String) -> some View {
229→        HStack(alignment: .top, spacing: FitTodaySpacing.md) {
230→            Image(systemName: icon)
231→                .font(.system(size: 20))
232→                .foregroundStyle(FitTodayColor.brandPrimary)
233→                .frame(width: 32)
234→
235→            VStack(alignment: .leading, spacing: 4) {
236→                Text(title)
237→                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
238→                    .foregroundStyle(FitTodayColor.textPrimary)
239→
240→                Text(description)
241→                    .font(FitTodayFont.ui(size: 14, weight: .medium))
242→                    .foregroundStyle(FitTodayColor.textSecondary)
243→            }
244→        }
245→    }
246→
247→    // MARK: - Connected Trainer Section
248→
249→    private var connectedTrainerSection: some View {
250→        VStack(spacing: FitTodaySpacing.lg) {
251→            if let trainer = viewModel.currentTrainer {
252→                // Trainer Card
253→                TrainerCard(trainer: trainer, variant: .expanded)
254→
255→                // Connection Status
256→                connectionStatusBadge
257→
258→                // Assigned Workouts
259→                if viewModel.isConnected {
260→                    assignedWorkoutsSection
261→                }
262→
263→                // Actions
264→                connectionActionsSection
265→            }
266→        }
267→    }
268→
269→    // MARK: - Connection Status Badge
270→
271→    private var connectionStatusBadge: some View {
272→        HStack(spacing: FitTodaySpacing.sm) {
273→            Circle()
274→                .fill(statusColor)
275→                .frame(width: 8, height: 8)
276→
277→            Text(statusText)
278→                .font(FitTodayFont.ui(size: 14, weight: .medium))
279→                .foregroundStyle(FitTodayColor.textSecondary)
280→        }
281→        .padding(.horizontal, FitTodaySpacing.md)
282→        .padding(.vertical, FitTodaySpacing.sm)
283→        .background(statusColor.opacity(0.1))
284→        .clipShape(Capsule())
285→    }
286→
287→    private var statusColor: Color {
288→        switch viewModel.connectionStatus {
289→        case .active: return FitTodayColor.success
290→        case .pending: return FitTodayColor.warning
291→        case .paused: return FitTodayColor.info
292→        case .cancelled: return FitTodayColor.error
293→        case .none: return FitTodayColor.textSecondary
294→        }
295→    }
296→
297→    private var statusText: String {
298→        switch viewModel.connectionStatus {
299→        case .active: return "personal_trainer.status.active".localized
300→        case .pending: return "personal_trainer.status.pending".localized
301→        case .paused: return "personal_trainer.status.paused".localized
302→        case .cancelled: return "personal_trainer.status.cancelled".localized
303→        case .none: return "personal_trainer.status.none".localized
304→        }
305→    }
306→
307→    // MARK: - Assigned Workouts Section
308→
309→    private var assignedWorkoutsSection: some View {
310→        VStack(alignment: .leading, spacing: FitTodaySpacing.md) {
311→            HStack {
312→                Text("personal_trainer.workouts.title".localized)
313→                    .font(FitTodayFont.ui(size: 18, weight: .bold))
314→                    .foregroundStyle(FitTodayColor.textPrimary)
315→
316→                Spacer()
317→
318→                if viewModel.pendingWorkoutsCount > 0 {
319→                    Text("personal_trainer.workouts.pending_count".localized(with: viewModel.pendingWorkoutsCount))
320→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
321→                        .foregroundStyle(FitTodayColor.brandPrimary)
322→                        .padding(.horizontal, 8)
323→                        .padding(.vertical, 4)
324→                        .background(FitTodayColor.brandPrimary.opacity(0.1))
325→                        .clipShape(Capsule())
326→                }
327→            }
328→
329→            if viewModel.assignedWorkouts.isEmpty {
330→                Text("personal_trainer.workouts.empty".localized)
331→                    .font(FitTodayFont.ui(size: 14, weight: .medium))
332→                    .foregroundStyle(FitTodayColor.textSecondary)
333→                    .frame(maxWidth: .infinity)
334→                    .padding()
335→            } else {
336→                ForEach(viewModel.assignedWorkouts) { workout in
337→                    Button {
338→                        router.push(.cmsWorkoutDetail(workout.id), on: .workout)
339→                    } label: {
340→                        AssignedWorkoutRow(workout: workout)
341→                    }
342→                    .buttonStyle(.plain)
343→                }
344→            }
345→        }
346→        .padding()
347→        .background(FitTodayColor.surface)
348→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.lg))
349→    }
350→
351→    // MARK: - Connection Actions Section
352→
353→    private var connectionActionsSection: some View {
354→        VStack(spacing: FitTodaySpacing.sm) {
355→            if viewModel.isPending {
356→                Button {
357→                    Task {
358→                        await viewModel.cancelConnection()
359→                    }
360→                } label: {
361→                    HStack {
362→                        Image(systemName: "xmark.circle")
363→                        Text("personal_trainer.actions.cancel_request".localized)
364→                    }
365→                }
366→                .fitSecondaryStyle()
367→            } else if viewModel.isConnected {
368→                Button(role: .destructive) {
369→                    Task {
370→                        await viewModel.cancelConnection()
371→                    }
372→                } label: {
373→                    HStack {
374→                        Image(systemName: "person.badge.minus")
375→                        Text("personal_trainer.actions.disconnect".localized)
376→                    }
377→                }
378→                .fitSecondaryStyle()
379→            }
380→        }
381→    }
382→}
383→
384→// MARK: - Assigned Workout Row
385→
386→private struct AssignedWorkoutRow: View {
387→    let workout: TrainerWorkout
388→
389→    private var exerciseCount: Int {
390→        workout.phases.reduce(0) { $0 + $1.items.count }
391→    }
392→
393→    private var scheduledDate: Date? {
394→        workout.schedule.scheduledDate
395→    }
396→
397→    var body: some View {
398→        HStack(spacing: FitTodaySpacing.md) {
399→            // Icon
400→            ZStack {
401→                Circle()
402→                    .fill(workout.isActive ? FitTodayColor.brandPrimary.opacity(0.1) : FitTodayColor.textSecondary.opacity(0.1))
403→                    .frame(width: 44, height: 44)
404→
405→                Image(systemName: workout.isActive ? "dumbbell.fill" : "checkmark.circle.fill")
406→                    .font(.system(size: 20))
407→                    .foregroundStyle(workout.isActive ? FitTodayColor.brandPrimary : FitTodayColor.success)
408→            }
409→
410→            // Content
