166→protocol GetCurrentTrainerUseCaseProtocol: Sendable {
167→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)?
168→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?>
169→}
