  7→
  8→import Foundation
  9→
 10→// MARK: - Firebase Personal Trainer Repository
 11→
 12→/// Firebase implementation of personal trainer and trainer-student repositories.
 13→///
 14→/// Uses `FirebasePersonalTrainerService` for Firestore operations and
 15→/// `PersonalTrainerMapper` for DTO-to-domain conversions.
 16→final class FirebasePersonalTrainerRepository: PersonalTrainerRepository, TrainerStudentRepository, @unchecked Sendable {
 17→
 18→    private let service: FirebasePersonalTrainerService
 19→
 20→    // MARK: - Initialization
 21→
 22→    init(service: FirebasePersonalTrainerService = FirebasePersonalTrainerService()) {
 23→        self.service = service
 24→    }
 25→
 26→    // MARK: - PersonalTrainerRepository
 27→
 28→    func fetchTrainer(id: String) async throws -> PersonalTrainer {
 29→        do {
 30→            let fbTrainer = try await service.fetchTrainer(id: id)
 31→            return PersonalTrainerMapper.toDomain(fbTrainer, id: id)
 32→        } catch let error as NSError {
 33→            if error.code == 404 {
 34→                throw DomainError.notFound(resource: "Personal Trainer")
 35→            }
 36→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 37→        }
 38→    }
 39→
 40→    func searchTrainers(query: String, limit: Int) async throws -> [PersonalTrainer] {
 41→        do {
 42→            let results = try await service.searchTrainers(query: query, limit: limit)
 43→            return results.map { PersonalTrainerMapper.toDomain($0.1, id: $0.0) }
 44→        } catch {
 45→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 46→        }
 47→    }
 48→
 49→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
 50→        do {
 51→            guard let result = try await service.findByInviteCode(code) else {
 52→                return nil
 53→            }
 54→            return PersonalTrainerMapper.toDomain(result.1, id: result.0)
 55→        } catch {
 56→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 57→        }
 58→    }
 59→
 60→    // MARK: - TrainerStudentRepository
 61→
 62→    func requestConnection(
 63→        trainerId: String,
 64→        studentId: String,
 65→        studentDisplayName: String
 66→    ) async throws -> String {
 67→        do {
 68→            return try await service.requestConnection(
 69→                trainerId: trainerId,
 70→                studentId: studentId,
 71→                studentDisplayName: studentDisplayName
 72→            )
 73→        } catch let error as NSError {
 74→            switch error.code {
 75→            case 409:
 76→                throw DomainError.invalidInput(reason: "Connection already exists with this trainer")
 77→            default:
 78→                throw DomainError.repositoryFailure(reason: error.localizedDescription)
 79→            }
 80→        }
 81→    }
 82→
 83→    func cancelConnection(relationshipId: String) async throws {
 84→        do {
 85→            try await service.cancelConnection(relationshipId: relationshipId)
 86→        } catch {
 87→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 88→        }
 89→    }
 90→
 91→    func getCurrentRelationship(studentId: String) async throws -> TrainerStudentRelationship? {
 92→        do {
 93→            guard let result = try await service.getCurrentRelationship(studentId: studentId) else {
 94→                return nil
 95→            }
 96→            return PersonalTrainerMapper.toRelationship(result.1, id: result.0)
 97→        } catch {
 98→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 99→        }
100→    }
101→
102→    func observeRelationship(studentId: String) -> AsyncStream<TrainerStudentRelationship?> {
103→        AsyncStream { continuation in
104→            Task {
105→                let stream = await service.observeRelationship(studentId: studentId)
106→                for await result in stream {
107→                    if let (id, fbRelationship) = result {
108→                        let relationship = PersonalTrainerMapper.toRelationship(fbRelationship, id: id)
109→                        continuation.yield(relationship)
110→                    } else {
111→                        continuation.yield(nil)
112→                    }
113→                }
114→                continuation.finish()
115→            }
116→        }
117→    }
118→}
