//
//  TrainerChatView.swift
//  FitToday
//
//  Chat interface for communicating with a personal trainer.
//

import SwiftUI
import Swinject

struct TrainerChatView: View {
    @State private var viewModel: TrainerChatViewModel

    init(trainerId: String, trainerName: String, currentUserId: String, resolver: Resolver) {
        _viewModel = State(wrappedValue: TrainerChatViewModel(
            trainerId: trainerId,
            trainerName: trainerName,
            currentUserId: currentUserId,
            resolver: resolver
        ))
    }

    var body: some View {
        VStack(spacing: 0) {
            if viewModel.isLoading {
                Spacer()
                ProgressView()
                    .tint(FitTodayColor.brandPrimary)
                Spacer()
            } else if viewModel.isEmpty {
                Spacer()
                emptyState
                Spacer()
            } else {
                messagesView
            }

            Divider()
                .overlay(FitTodayColor.outline)

            inputBar
        }
        .background(FitTodayColor.background)
        .task {
            await viewModel.startListening()
        }
        .onDisappear {
            viewModel.stopListening()
        }
    }

    // MARK: - Messages

    private var messagesView: some View {
        ScrollViewReader { proxy in
            ScrollView {
                LazyVStack(spacing: FitTodaySpacing.sm) {
                    ForEach(viewModel.messages) { message in
                        ChatBubble(
                            message: message,
                            isFromCurrentUser: viewModel.isFromCurrentUser(message)
                        )
                        .id(message.id)
                    }
                }
                .padding(.horizontal, FitTodaySpacing.md)
                .padding(.vertical, FitTodaySpacing.sm)
            }
            .scrollIndicators(.hidden)
            .onChange(of: viewModel.messages.count) {
                if let lastId = viewModel.messages.last?.id {
                    withAnimation {
                        proxy.scrollTo(lastId, anchor: .bottom)
                    }
                }
            }
        }
    }

    // MARK: - Empty State

    private var emptyState: some View {
        VStack(spacing: FitTodaySpacing.md) {
            Image(systemName: "message")
                .font(.system(size: 40))
                .foregroundStyle(FitTodayColor.textTertiary)

            Text("trainer.chat.empty".localized)
                .font(FitTodayFont.ui(size: 14, weight: .medium))
                .foregroundStyle(FitTodayColor.textSecondary)
        }
    }

    // MARK: - Input Bar

    private var inputBar: some View {
        HStack(spacing: FitTodaySpacing.sm) {
            TextField("trainer.chat.placeholder".localized, text: $viewModel.newMessageText, axis: .vertical)
                .font(FitTodayFont.ui(size: 14, weight: .medium))
                .foregroundStyle(FitTodayColor.textPrimary)
                .lineLimit(1...4)
                .padding(.horizontal, FitTodaySpacing.md)
                .padding(.vertical, 10)
                .background(FitTodayColor.surface)
                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))

            Button {
                viewModel.sendMessage()
            } label: {
                Image(systemName: "arrow.up.circle.fill")
                    .font(.system(size: 32))
                    .foregroundStyle(viewModel.canSend ? FitTodayColor.brandPrimary : FitTodayColor.textTertiary)
            }
            .buttonStyle(.plain)
            .disabled(!viewModel.canSend)
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
        .background(FitTodayColor.backgroundElevated)
    }
}

//
//  TrainerChatViewModel.swift
//  FitToday
//
//  ViewModel for trainer chat interface with Firestore real-time messaging.
//

import Foundation
import Swinject

@MainActor
@Observable final class TrainerChatViewModel {
    private(set) var messages: [TrainerChatMessage] = []
    var newMessageText = ""
    private(set) var isLoading = false
    private(set) var isEmpty = false
    private(set) var error: Error?

    private let trainerId: String
    private let trainerName: String
    private let currentUserId: String
    private let chatService: TrainerChatServiceProtocol?

    nonisolated(unsafe) private var listenerTask: Task<Void, Never>?

    var conversationId: String {
        let ids = [trainerId, currentUserId].sorted()
        return "\(ids[0])_\(ids[1])"
    }

    var canSend: Bool {
        !newMessageText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    init(trainerId: String, trainerName: String, currentUserId: String, resolver: Resolver) {
        self.trainerId = trainerId
        self.trainerName = trainerName
        self.currentUserId = currentUserId
        self.chatService = resolver.resolve(TrainerChatServiceProtocol.self)
    }

    deinit {
        let task = listenerTask
        task?.cancel()
    }

    // MARK: - Start Listening

    func startListening() async {
        guard let chatService, listenerTask == nil else { return }

        isLoading = true

        // Mark messages as read when opening
        try? await chatService.markMessagesAsRead(
            conversationId: conversationId,
            byUserId: currentUserId
        )

        listenerTask = Task {
            for await newMessages in chatService.observeMessages(conversationId: conversationId) {
                guard !Task.isCancelled else { break }
                self.messages = newMessages
                self.isEmpty = newMessages.isEmpty
                self.isLoading = false
            }
        }
    }

    // MARK: - Send Message

    func sendMessage() {
        guard canSend, let chatService else { return }
        let content = newMessageText.trimmingCharacters(in: .whitespacesAndNewlines)
        newMessageText = ""

        // Optimistic append
        let optimisticMessage = TrainerChatMessage(
            id: UUID().uuidString,
            conversationId: conversationId,
            senderId: currentUserId,
            content: content,
            type: .text,
            createdAt: Date(),
            isRead: false
        )
        messages.append(optimisticMessage)

        Task {
            do {
                try await chatService.sendMessage(
                    conversationId: conversationId,
                    senderId: currentUserId,
                    content: content
                )
            } catch {
                // Remove optimistic message on failure
                messages.removeAll { $0.id == optimisticMessage.id }
                self.error = error
            }
        }
    }

    func isFromCurrentUser(_ message: TrainerChatMessage) -> Bool {
        message.senderId == currentUserId
    }

    // MARK: - Stop Listening

    func stopListening() {
        listenerTask?.cancel()
        listenerTask = nil
    }
}

